parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "newsletter_title": {
      "type": "string",
      "description": "Title of the newsletter"
    },
    "newsletter_intro": {
      "type": "string",
      "description": "Short introduction for the newsletter"
    },
    "articles": {
      "type": "array",
      "description": "List of summarized articles",
      "items": {
        "type": "object",
        "properties": {
          "title": {
            "type": "string",
            "description": "Title of the article"
          },
          "summary": {
            "type": "string",
            "description": "Short summary of the article"
          },
          "url": {
            "type": "string",
            "description": "Source link of the article"
          }
        },
        "required": ["title", "summary", "url"]
      }
    },
    "closing": {
      "type": "string",
      "description": "Closing message for the newsletter"
    }
  },
  "required": ["newsletter_title", "newsletter_intro", "articles", "closing"]
}
